def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 1.0:
            if ratio < 1.1:
                priority = ((ratio - 1) ** 3) * 350 + 25
                for j in range(1, 5):
                    priority += np.cos(np.pi * ratio * j) * 3 / j
            elif ratio < 1.8:
                priority = (ratio - 1.1) * 270 + 50
                mod_check = [2, 5, 8]
                added_mod = False
                for mod_val in mod_check:
                    if capacity % mod_val == 0:
                        priority += 3.3 * (mod_val / 2)
                        added_mod = True
                        break
                if not added_mod:
                    priority += 1.5
                for k in range(1, 6):
                    priority += ((-1) ** k) * np.sqrt(k + capacity) / (k + 2) * 1.1
            elif ratio < 2.7:
                priority = ((ratio - 1.8) ** 2) * 400 + 75
                for m in range(1, 4):
                    priority -= np.sin(ratio * m * np.pi / 2) * (m ** 2)
                if capacity % 9 == 0:
                    priority += 4.4
                elif capacity % 11 == 0:
                    priority += 3.1
                if ratio > 2.3:
                    priority += (ratio - 2.3) ** 3 * 150
            else:
                val = (ratio - 2.7)
                priority = np.exp(val) * 100 + 120
                for n in range(1, 5):
                    priority -= (val ** n) * (10 / n)
                priority = min(priority, 200)
        else:
            series_sum = 0.0
            for p in range(1, 12):
                factor = ((-1) ** (p + 1)) * (ratio ** (p * 1.3)) / (p * 1.3)
                if p % 4 == 0:
                    factor *= 1.9
                series_sum += factor
            priority += abs(series_sum) * 2.1
            if capacity < item * 1.5:
                priority *= 3.2
            log_comp = np.log(capacity + 3) - np.log(item + 2)
            if log_comp > 0:
                priority += 11 / log_comp
            else:
                priority += 38
            if capacity % 4 == 0 and capacity % 6 == 0:
                priority += 1.5
            elif capacity % 3 == 0:
                priority += 0.9
            else:
                priority -= 0.6
            if ratio < 0.25:
                for q in range(1, 7):
                    add_term = ((-1) ** (q + 1)) * (ratio ** (q * 2.3)) * (q * 0.9)
                    if q == 5 and capacity > item * 6:
                        add_term *= 1.4
                    priority += add_term
            if capacity > 4 * item:
                priority -= 4.2
            if capacity % 8 == 0 and ratio < 0.45:
                priority -= 1.7
            if capacity > item * 10:
                for r in range(2, 8):
                    root_r = np.cbrt(r)
                    power_term = ratio ** (1 / (r + 0.5))
                    sign_term = (-1) ** (r + 1)
                    priority += root_r * power_term * sign_term * (r * 0.4)
            if priority > 65:
                priority = 65 + np.log(priority - 64) * 1.8
            if priority < 0:
                priority = 0
        priorities[i] = priority
    return priorities
